{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a topological embedding task. To maximize empty cells (E), we need to find the smallest possible representation of the color adjacency graph. This involves graph theory (finding a planar or near-planar embedding) and grid-based layout optimization.",
  "helpers": [
    {
      "label": "graph_analyzer",
      "instructions": "Parse the 50x50 input grid to construct an adjacency graph where nodes are colors 1 to M. Determine the degree of each node and identify the adjacency relations. Check if the graph is planar or has specific properties that would allow for a sparse grid embedding."
    },
    {
      "label": "layout_optimizer",
      "instructions": "Given a graph of color adjacencies, propose a set of coordinates (x, y) for each color 1 to M such that adjacent colors are placed in cells that are orthogonally adjacent in a 50x50 grid. The goal is to minimize the number of non-zero cells used, effectively maximizing the number of 0 cells. Ensure no two colors occupy the same cell and that the connectivity of each color is maintained (though for a single cell per color, connectivity is trivial)."
    },
    {
      "label": "grid_generator",
      "instructions": "Take the coordinate mapping from the layout optimizer and generate a 50x50 integer grid. Fill the grid with 0s by default, then place the specified color at its assigned (x, y) coordinate. Ensure the output format strictly follows the 50 lines of 50 integers requirement."
    }
  ],
  "synthesis_brief": "The parent will use the graph_analyzer to understand the constraints, the layout_optimizer to find a minimal set of coordinates that satisfies the adjacency requirements, and the grid_generator to produce the final 50x50 output grid for submission."
}

